use distributed_inference::pleromatic_frame::PleromaticFrame;
use distributed_inference::rf_physics_cpu::RfPhysicsCpuObservation;
use serde::Serialize;
use std::env;
use std::fs;

#[derive(Serialize)]
struct ProbeReport {
    input_frame: String,
    source_id: String,
    is_waterfall: bool,
    byte_count: usize,
    max_energy: u8,
    mean_energy: f32,
    observation: RfPhysicsCpuObservation,
    projected_frame: PleromaticFrame,
}

fn arg_value(name: &str, default: &str) -> String {
    let mut args = env::args().skip(1);
    while let Some(arg) = args.next() {
        if arg == name {
            return args.next().unwrap_or_else(|| default.to_string());
        }
    }
    default.to_string()
}

fn main() -> Result<(), Box<dyn std::error::Error>> {
    let input = arg_value("--input", "spectrum_waterfall.frame");
    let threshold = arg_value("--threshold", "20").parse::<u16>()?;
    let bytes = fs::read(&input)?;
    let frame: PleromaticFrame = bincode::deserialize(&bytes)?;
    let max_energy = frame.data.iter().copied().max().unwrap_or(0);
    let mean_energy = if frame.data.is_empty() {
        0.0
    } else {
        frame.data.iter().map(|&v| v as f32).sum::<f32>() / frame.data.len() as f32
    };
    let observation = RfPhysicsCpuObservation::observe_waterfall_frame(&frame, threshold);
    let projected_frame = observation.to_monster_mesh_frame(format!("rf_cpu:{}", frame.source_id));
    let report = ProbeReport {
        input_frame: input,
        source_id: frame.source_id.clone(),
        is_waterfall: frame.is_spectrogram_waterfall(),
        byte_count: frame.data.len(),
        max_energy,
        mean_energy,
        observation,
        projected_frame,
    };

    println!("{}", serde_json::to_string_pretty(&report)?);
    Ok(())
}
